`WebServer.h` from the ESP32 Arduino core handles routing. Keep handlers short; long work blocks `loop()`.

```cpp
#include <Arduino.h>
#include <WiFi.h>
#include <WebServer.h>

const char* SSID = "your-ssid";
const char* PASS = "your-password";

WebServer server(80);

void handleUptime() {
  String body = String("{\"uptime_ms\":") + millis() + "}";
  server.send(200, "application/json", body);
}

void setup() {
  Serial.begin(115200);
  WiFi.begin(SSID, PASS);
  while (WiFi.status() != WL_CONNECTED) delay(250);
  Serial.println(WiFi.localIP());

  server.on("/uptime", handleUptime);
  server.begin();
}

void loop() {
  server.handleClient();
}
```

For HTTPS without per-cert pinning, `setInsecure()` is the path of least resistance. For production, ship the cert bundle.

```cpp
#include <Arduino.h>
#include <WiFi.h>
#include <WiFiClientSecure.h>
#include <HTTPClient.h>

const char* SSID = "your-ssid";
const char* PASS = "your-password";
const char* URL  = "https://example.com/ingest";

uint32_t lastPost = 0;

void postOnce(float t) {
  WiFiClientSecure client;
  client.setInsecure();
  HTTPClient http;
  if (!http.begin(client, URL)) return;
  http.addHeader("Content-Type", "application/json");
  String body = String("{\"t\":") + String(t, 2) + "}";
  int code = http.POST(body);
  Serial.printf("POST %d\n", code);
  http.end();
}

void setup() {
  Serial.begin(115200);
  WiFi.begin(SSID, PASS);
  while (WiFi.status() != WL_CONNECTED) delay(250);
}

void loop() {
  if (millis() - lastPost >= 60000) {
    lastPost = millis();
    postOnce(23.4f);
  }
}
```

