AsyncMqttClient (Marvin Roger) plays well with the ESP32 Arduino async stack and survives WiFi flaps cleanly.

```cpp
#include <Arduino.h>
#include <WiFi.h>
#include <AsyncMqttClient.h>

const char* SSID    = "your-ssid";
const char* PASS    = "your-password";
const char* MQTT_HOST = "broker.local";
const uint16_t MQTT_PORT = 1883;

AsyncMqttClient mqtt;
uint32_t lastHb = 0;

void onMqttConnect(bool sessionPresent) {
  Serial.println("mqtt connected");
}
void onMqttDisconnect(AsyncMqttClientDisconnectReason r) {
  Serial.printf("mqtt down: %d\n", (int)r);
}

void setup() {
  Serial.begin(115200);
  WiFi.begin(SSID, PASS);
  while (WiFi.status() != WL_CONNECTED) delay(250);

  mqtt.onConnect(onMqttConnect);
  mqtt.onDisconnect(onMqttDisconnect);
  mqtt.setServer(MQTT_HOST, MQTT_PORT);
  mqtt.connect();
}

void loop() {
  if (millis() - lastHb >= 10000) {
    lastHb = millis();
    if (mqtt.connected()) {
      mqtt.publish("feather/hb", 0, false, String(millis()).c_str());
    }
  }
}
```

