WiFi on the R4 goes through the ESP32-S3 coprocessor; the Arduino-side library is `WiFiS3`.

```cpp
#include <Arduino.h>
#include <WiFiS3.h>

void setup() {
  Serial.begin(115200);
  while (!Serial && millis() < 2000);

  int n = WiFi.scanNetworks();
  Serial.printf("found %d networks\n", n);
  for (int i = 0; i < n; i++) {
    Serial.printf("%2d  %-32s  %ld dBm\n", i + 1, WiFi.SSID(i), WiFi.RSSI(i));
  }
}

void loop() {}
```

