`configTzTime` sets POSIX TZ + NTP servers in one call, which keeps DST handling correct.

```cpp
#include <Arduino.h>
#include <WiFi.h>
#include <time.h>

const char* SSID = "your-ssid";
const char* PASS = "your-password";
const char* TZ   = "UTC0";  // pick your TZ string

uint32_t lastReport = 0;

void setup() {
  Serial.begin(115200);
  WiFi.begin(SSID, PASS);
  while (WiFi.status() != WL_CONNECTED) delay(250);
  configTzTime(TZ, "pool.ntp.org", "time.google.com");
}

void loop() {
  if (millis() - lastReport < 10000) return;
  lastReport = millis();

  struct tm tm_now;
  if (!getLocalTime(&tm_now, 50)) {
    Serial.println("no time yet");
    return;
  }
  char buf[32];
  strftime(buf, sizeof(buf), "%Y-%m-%dT%H:%M:%SZ", &tm_now);
  Serial.println(buf);
}
```

`WiFiClient` is the synchronous TCP client. Always check `connect()` return so the print() doesn't hang.

```cpp
#include <Arduino.h>
#include <WiFi.h>

const char* SSID = "your-ssid";
const char* PASS = "your-password";
const IPAddress HOST(192, 168, 1, 10);
const uint16_t PORT = 8000;

void setup() {
  Serial.begin(115200);
  WiFi.begin(SSID, PASS);
  while (WiFi.status() != WL_CONNECTED) delay(250);

  WiFiClient client;
  if (!client.connect(HOST, PORT, 3000)) {
    Serial.println("connect failed");
    return;
  }
  client.println("hello from xiao");
  client.stop();
}

void loop() {}
```
